        // Case 1: Subsequence of length 1. GCD is b_i. We need b_i = 1.
        if b.iter().any(|&x| x == 1) {
            // If there is an element equal to p (so b_i=1), the subsequence [p] has GCD p, length 1 (< n since n>=2).
            return true;
        }

