    for q in queries.iter() {
        let idx = q[0] as usize;
        let val = q[1];

        // 1. Update the array
        current_nums[idx] = val;

        // 2. Check for good subsequence existence
        if check_good_subsequence(&current_nums, p, n) {
            good_subsequence_count += 1;
        }
    }

    good_subsequence_count
